import React, { useContext, useEffect, useState } from 'react';
import { Pressable, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import { AuthContext } from '../../App';
import AppIcon from '../components/AppIcon';
import ScreenHeader from '../components/ScreenHeader';
import { updateUserProfile } from '../services/firebaseService';
import { createShadow } from '../styles/shadows';
import { theme } from '../styles/theme';

const ProfileScreen = () => {
  const { profile, signOut, refreshProfile } = useContext(AuthContext);
  const [address, setAddress] = useState('');
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    setAddress(profile?.address ?? '');
  }, [profile]);

  const handleSave = async () => {
    if (!profile) {
      return;
    }
    setSaving(true);
    setMessage('');
    try {
      await updateUserProfile(profile.uid, { address: address.trim() });
      await refreshProfile();
      setMessage('Address saved.');
    } catch (error: any) {
      setMessage(error.message || 'Unable to save your address.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <ScreenHeader
          back
          title="Profile"
          subtitle="Account details, role information, and delivery address in one clean space."
        />

        <View style={styles.heroCard}>
          <View style={styles.avatar}>
            <AppIcon name="person" size={30} color={theme.colors.primary} />
          </View>
          <View style={styles.heroBody}>
            <Text style={styles.name}>{profile?.name ?? 'Unknown user'}</Text>
            <Text style={styles.meta}>{profile?.phone ?? 'No phone available'}</Text>
            <View style={styles.badgeRow}>
              <View style={styles.badge}>
                <AppIcon name={profile?.role === 'owner' ? 'business-outline' : 'home-outline'} size={14} color={theme.colors.primary} />
                <Text style={styles.badgeText}>{profile?.role === 'owner' ? 'Owner' : 'Customer'}</Text>
              </View>
              {profile?.role === 'customer' ? (
                <View style={[styles.badge, profile.approved ? styles.approvedBadge : styles.pendingBadge]}>
                  <AppIcon
                    name={profile.approved ? 'checkmark-circle' : 'time-outline'}
                    size={14}
                    color={profile.approved ? theme.colors.secondary : theme.colors.warning}
                  />
                  <Text style={styles.badgeText}>{profile.approved ? 'Approved' : 'Pending approval'}</Text>
                </View>
              ) : null}
            </View>
          </View>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Delivery address</Text>
          <Text style={styles.sectionSubtitle}>Keep this updated so the order flow stays quick.</Text>
          <TextInput
            style={styles.input}
            value={address}
            onChangeText={setAddress}
            placeholder="Add your delivery address"
            placeholderTextColor={theme.colors.textTertiary}
            multiline
            numberOfLines={4}
          />
          <Pressable style={[styles.primaryButton, saving && styles.disabled]} onPress={handleSave} disabled={saving}>
            <AppIcon name="save-outline" size={18} color="#fff" />
            <Text style={styles.primaryButtonText}>{saving ? 'Saving...' : 'Save address'}</Text>
          </Pressable>
          {message ? <Text style={styles.messageText}>{message}</Text> : null}
        </View>

        <Pressable style={styles.signOutButton} onPress={signOut}>
          <AppIcon name="log-out-outline" size={18} color={theme.colors.danger} />
          <Text style={styles.signOutText}>Sign out</Text>
        </Pressable>
      </View>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: theme.colors.background
  },
  content: {
    flex: 1,
    padding: 18
  },
  heroCard: {
    flexDirection: 'row',
    gap: 14,
    borderRadius: 28,
    padding: 20,
    backgroundColor: theme.colors.surface,
    borderWidth: 1,
    borderColor: theme.colors.stroke,
    ...createShadow({ color: '#163456', opacity: 0.1, radius: 18, elevation: 6 })
  },
  avatar: {
    width: 64,
    height: 64,
    borderRadius: 32,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: theme.colors.primarySoft
  },
  heroBody: {
    flex: 1
  },
  name: {
    color: theme.colors.text,
    fontSize: 24,
    fontWeight: '800'
  },
  meta: {
    marginTop: 6,
    color: theme.colors.textSecondary,
    fontSize: 14
  },
  badgeRow: {
    marginTop: 12,
    flexDirection: 'row',
    gap: 8,
    flexWrap: 'wrap'
  },
  badge: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
    backgroundColor: theme.colors.surfaceMuted,
    borderRadius: theme.radius.pill,
    paddingHorizontal: 10,
    paddingVertical: 8
  },
  approvedBadge: {
    backgroundColor: '#F1FBF4'
  },
  pendingBadge: {
    backgroundColor: '#FFF7EA'
  },
  badgeText: {
    color: theme.colors.text,
    fontSize: 12,
    fontWeight: '700'
  },
  card: {
    marginTop: 16,
    borderRadius: 28,
    padding: 20,
    backgroundColor: theme.colors.surface,
    borderWidth: 1,
    borderColor: theme.colors.stroke,
    ...createShadow({ color: '#163456', opacity: 0.1, radius: 18, elevation: 6 })
  },
  sectionTitle: {
    color: theme.colors.text,
    fontSize: 20,
    fontWeight: '800'
  },
  sectionSubtitle: {
    marginTop: 6,
    color: theme.colors.textSecondary,
    fontSize: 14,
    lineHeight: 21
  },
  input: {
    marginTop: 16,
    borderRadius: 22,
    padding: 16,
    minHeight: 112,
    textAlignVertical: 'top',
    color: theme.colors.text,
    backgroundColor: theme.colors.surfaceMuted,
    borderWidth: 1,
    borderColor: theme.colors.stroke
  },
  primaryButton: {
    marginTop: 16,
    borderRadius: 18,
    backgroundColor: theme.colors.primary,
    paddingVertical: 15,
    alignItems: 'center',
    justifyContent: 'center',
    flexDirection: 'row',
    gap: 8
  },
  primaryButtonText: {
    color: '#fff',
    fontSize: 15,
    fontWeight: '800'
  },
  disabled: {
    opacity: 0.7
  },
  messageText: {
    marginTop: 12,
    color: theme.colors.textSecondary,
    fontWeight: '600'
  },
  signOutButton: {
    marginTop: 16,
    borderRadius: 18,
    paddingVertical: 15,
    backgroundColor: '#FFF4F3',
    alignItems: 'center',
    justifyContent: 'center',
    flexDirection: 'row',
    gap: 8
  },
  signOutText: {
    color: theme.colors.danger,
    fontSize: 15,
    fontWeight: '800'
  }
});

export default ProfileScreen;
